import{_ as s,o as e,c as l,O as o}from"./chunks/framework.3442b110.js";const E=JSON.parse('{"title":"API 引导","description":"","frontmatter":{},"headers":[],"relativePath":"zh/api/guide.md","filePath":"zh/api/guide.md","lastUpdated":1713183154000}'),t={name:"zh/api/guide.md"};function n(p,a,c,r,d,i){return e(),l("div",null,[...a[0]||(a[0]=[o(`<h1 id="api-引导" tabindex="-1">API 引导 <a class="header-anchor" href="#api-引导" aria-label="Permalink to &quot;API 引导&quot;">​</a></h1><blockquote><p>推荐先从 <a href="./../start/core">快速入门</a> 开始阅读</p></blockquote><p>根据<a href="./../start/core">快速入门</a>中的知识，大家应该对多维表格的模型有了一个初步的了解，这篇文章，帮助大家简单强化理解一下这个模型，便于插件的设计以及 API 的查询。</p><p><code>bitable</code>，是所有 API 的统一入口，不同的功能模块均会挂载至该统一入口。</p><h2 id="base-模块" tabindex="-1">Base 模块 <a class="header-anchor" href="#base-模块" aria-label="Permalink to &quot;Base 模块&quot;">​</a></h2><p>绝大部分的 API 调用方法都是从 <code>base</code> 调用的，因为对多维表格进行增删改查的 API 都位于 <code>base</code> 下，大部分 Case 如下所示：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">import</span><span style="color:#E1E4E8;"> { bitable } </span><span style="color:#F97583;">from</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">&#39;@lark-base-open/js-sdk&#39;</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F97583;">const</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">table</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> bitable.base.</span><span style="color:#B392F0;">getActiveTable</span><span style="color:#E1E4E8;">();</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">import</span><span style="color:#24292E;"> { bitable } </span><span style="color:#D73A49;">from</span><span style="color:#24292E;"> </span><span style="color:#032F62;">&#39;@lark-base-open/js-sdk&#39;</span><span style="color:#24292E;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D73A49;">const</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">table</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">await</span><span style="color:#24292E;"> bitable.base.</span><span style="color:#6F42C1;">getActiveTable</span><span style="color:#24292E;">();</span></span></code></pre></div><p><code>getActiveTable</code> 的作用是来获取当前页面已经选择的 <code>table</code>，在 <code>base</code> 上还有很多接口可以用来获取 <code>table</code>，可以在 <code>Base</code> 模块的<a href="./base">文档</a>内查看。</p><h2 id="table-模块与-field-模块" tabindex="-1">Table 模块与 Field 模块 <a class="header-anchor" href="#table-模块与-field-模块" aria-label="Permalink to &quot;Table 模块与 Field 模块&quot;">​</a></h2><p>获取到 <code>table</code> 之后，就可以做很多数据相关的增删改查操作。</p><p>推荐开发者从 <code>field(字段)</code> 的角度来对数据进行增删改差，因为数据每一个单元格内的数据是由其所属的字段类型决定的，因此在通过字段来实现增删改查的时候，会给予更多的类型提示，下面是一个例子：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">attachmentField</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> table.</span><span style="color:#B392F0;">getField</span><span style="color:#E1E4E8;">&lt;</span><span style="color:#B392F0;">IAttachmentField</span><span style="color:#E1E4E8;">&gt;(fieldId);</span></span>
<span class="line"><span style="color:#F97583;">const</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">attachmentCell</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> attachmentField.</span><span style="color:#B392F0;">createCell</span><span style="color:#E1E4E8;">(file);</span></span>
<span class="line"><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> table.</span><span style="color:#B392F0;">addRecord</span><span style="color:#E1E4E8;">(attachmentCell);</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">const</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">attachmentField</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">await</span><span style="color:#24292E;"> table.</span><span style="color:#6F42C1;">getField</span><span style="color:#24292E;">&lt;</span><span style="color:#6F42C1;">IAttachmentField</span><span style="color:#24292E;">&gt;(fieldId);</span></span>
<span class="line"><span style="color:#D73A49;">const</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">attachmentCell</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">await</span><span style="color:#24292E;"> attachmentField.</span><span style="color:#6F42C1;">createCell</span><span style="color:#24292E;">(file);</span></span>
<span class="line"><span style="color:#D73A49;">await</span><span style="color:#24292E;"> table.</span><span style="color:#6F42C1;">addRecord</span><span style="color:#24292E;">(attachmentCell);</span></span></code></pre></div><p>在这个例子中，我们通过 <code>fieldId</code> 来获取了一个 <code>attachmentField(附件字段)</code>，在获取这个字段的时候，我们传入了一个很重要的东西 <code>IAttachemntField</code>，这是一个类型参数，告诉 ts 我们获取的是一个附件字段， 因此在后续调用 <code>attachmentField.createCell(file)</code> 的时候，我们是可以获得足够的类型提示的，告诉我们可以通过直接传入一个 <code>File / File[] / FileList</code> 来构造出一个附件单元格。</p><p>然后我们调用 <code>table.addRecord(attachmentCell)</code> 方法，将这个单元格插入到了表格之中（添加了一条记录），<code>table.addRecord</code> 方法还支持传入 <code>Cell[]</code> 参数，从而创建出一条更为完整的数据。</p><p>除此之外，<code>IAttachmentField(附件字段)</code> 还有一些便于开发者使用的 API：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">attachmentUrls</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> attachmentField.</span><span style="color:#B392F0;">getAttachmentUrls</span><span style="color:#E1E4E8;">(recordId)</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">const</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">attachmentUrls</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">await</span><span style="color:#24292E;"> attachmentField.</span><span style="color:#6F42C1;">getAttachmentUrls</span><span style="color:#24292E;">(recordId)</span></span></code></pre></div><p>因为附件字段中存储的并不是真正的 URL，所以在获取真正的 URL 时，需要多步，但是从字段本身的角度去考虑，我们在实现这个 API 的时候，就可以把这些工作放在字段自身的方法里实现， 所以还是非常推荐用户对数据的增删改查以及字段属性的设置可以从字段角度去考量。</p><p>除了 <code>IAttachmentField(附件字段)</code> 以外，我们还细化了很多字段，可以从 <a href="./field">字段引导</a> 阅读更多资料，Table 模块也有更多的 API 方法来供给开发者使用。</p><h2 id="cell-模块" tabindex="-1">Cell 模块 <a class="header-anchor" href="#cell-模块" aria-label="Permalink to &quot;Cell 模块&quot;">​</a></h2><p>在上文中，通过 <code>attachmentField.creatCell</code> 方法构造出来的 <code>Cell</code> 也是一个非常重要的模块，在进行插入数据的操作时，我们推荐开发者通过 <code>Field</code> 来构造 <code>Cell</code>，来插入数据， 当一个 <code>Cell</code> 被成功插入到 <code>Table</code> 中去后，它会与一条数据进行关联，此时进行 <code>getValue/setValue</code> 时，都会与实时性的数据产生关联，按照上述的流程可以这样来改变对应单元格的值：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> attachmentCell.</span><span style="color:#B392F0;">setValue</span><span style="color:#E1E4E8;">(newFile)</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">await</span><span style="color:#24292E;"> attachmentCell.</span><span style="color:#6F42C1;">setValue</span><span style="color:#24292E;">(newFile)</span></span></code></pre></div><p>在 <code>setValue</code> 顺利执行之后，表格中对应单元格的值会发生改变，更多的 API 用法可以查看对应<a href="./cell">文档</a>。</p><h2 id="record-模块" tabindex="-1">Record 模块 <a class="header-anchor" href="#record-模块" aria-label="Permalink to &quot;Record 模块&quot;">​</a></h2><p>Record 模块主要用来存储<strong>行数据</strong>，API 可以查看对应<a href="./record">文档</a>。</p><h2 id="ui-模块" tabindex="-1">UI 模块 <a class="header-anchor" href="#ui-模块" aria-label="Permalink to &quot;UI 模块&quot;">​</a></h2><p>UI 模块提供与用户交互相关的能力，如切换数据表、切换视图等，详细 API 可查看<a href="./ui">UI 模块文档</a>。</p><h2 id="bridge-模块" tabindex="-1">Bridge 模块 <a class="header-anchor" href="#bridge-模块" aria-label="Permalink to &quot;Bridge 模块&quot;">​</a></h2><p>Bridge 模块提供了一些通用能力，如获取用户 id，获取当前环境信息等，详细 API 可查看 <a href="./bridge">Bridge 模块文档</a>。</p>`,28)])])}const h=s(t,[["render",n]]);export{E as __pageData,h as default};
